import React, { useState, useEffect } from 'react';
import { useTranslation } from 'react-i18next';
import { useNavigate } from 'react-router-dom';
import { 
  FaCalendarAlt, 
  FaClock, 
  FaUserMd, 
  FaSearch,
  FaFilter,
  FaMapMarkerAlt
} from 'react-icons/fa';

const Availability = () => {
  const { t } = useTranslation();
  const navigate = useNavigate();
  const [selectedDate, setSelectedDate] = useState('');
  const [selectedSpecialty, setSelectedSpecialty] = useState('');
  const [selectedLocation, setSelectedLocation] = useState('');
  const [availableSlots, setAvailableSlots] = useState([]);

  // Sample availability data
  const sampleAvailability = [
    {
      id: '1',
      doctor: 'Dr. Rajesh Kumar',
      specialty: 'Cardiology',
      location: 'Civil Hospital',
      slots: ['09:00', '10:00', '11:00', '14:00', '15:00'],
      available: true
    },
    {
      id: '2',
      doctor: 'Dr. Priya Sharma',
      specialty: 'Pediatrics',
      location: 'District Hospital',
      slots: ['09:30', '10:30', '11:30', '14:30', '15:30'],
      available: true
    },
    {
      id: '3',
      doctor: 'Dr. Amit Singh',
      specialty: 'General Medicine',
      location: 'Primary Health Center',
      slots: ['10:00', '11:00', '12:00', '16:00', '17:00'],
      available: true
    }
  ];

  const specialties = [
    'General Medicine',
    'Cardiology',
    'Pediatrics',
    'Dermatology',
    'Orthopedic',
    'Gynecology',
    'ENT'
  ];

  const locations = [
    'Civil Hospital',
    'District Hospital',
    'Primary Health Center',
    'Community Health Center',
    'Medical College Hospital'
  ];

  // Get today's date for min date
  const getTodayDate = () => {
    const today = new Date();
    return today.toISOString().split('T')[0];
  };

  // Get max date (30 days from today)
  const getMaxDate = () => {
    const maxDate = new Date();
    maxDate.setDate(maxDate.getDate() + 30);
    return maxDate.toISOString().split('T')[0];
  };

  // Filter availability based on selections
  const filteredAvailability = sampleAvailability.filter(item => {
    if (selectedSpecialty && item.specialty !== selectedSpecialty) return false;
    if (selectedLocation && item.location !== selectedLocation) return false;
    return true;
  });

  return (
    <div className="container mx-auto px-4 py-8">
      {/* Header */}
      <div className="mb-8">
        <h1 className="text-3xl font-bold text-gray-900 mb-2">
          Doctor {t('availability')}
        </h1>
        <p className="text-gray-600">
          Check available time slots for consultations
        </p>
      </div>

      {/* Filters */}
      <div className="bg-white rounded-lg shadow-sm border p-6 mb-8">
        <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
          {/* Date Selection */}
          <div className="form-group">
            <label className="label flex items-center gap-2">
              <FaCalendarAlt className="text-gray-400" />
              Select Date
            </label>
            <input
              type="date"
              value={selectedDate}
              onChange={(e) => setSelectedDate(e.target.value)}
              min={getTodayDate()}
              max={getMaxDate()}
              className="input"
            />
          </div>

          {/* Specialty Filter */}
          <div className="form-group">
            <label className="label flex items-center gap-2">
              <FaUserMd className="text-gray-400" />
              {t('specialty')}
            </label>
            <select
              value={selectedSpecialty}
              onChange={(e) => setSelectedSpecialty(e.target.value)}
              className="input"
            >
              <option value="">All Specialties</option>
              {specialties.map(specialty => (
                <option key={specialty} value={specialty}>
                  {specialty}
                </option>
              ))}
            </select>
          </div>

          {/* Location Filter */}
          <div className="form-group">
            <label className="label flex items-center gap-2">
              <FaMapMarkerAlt className="text-gray-400" />
              Location
            </label>
            <select
              value={selectedLocation}
              onChange={(e) => setSelectedLocation(e.target.value)}
              className="input"
            >
              <option value="">All Locations</option>
              {locations.map(location => (
                <option key={location} value={location}>
                  {location}
                </option>
              ))}
            </select>
          </div>
        </div>
      </div>

      {/* Availability Cards */}
      <div className="space-y-6">
        {filteredAvailability.map((doctor) => (
          <div key={doctor.id} className="bg-white rounded-lg shadow-sm border p-6">
            <div className="flex items-start justify-between mb-4">
              <div>
                <h3 className="text-xl font-semibold text-gray-900 mb-1">
                  {doctor.doctor}
                </h3>
                <p className="text-gray-600 mb-2">{doctor.specialty}</p>
                <div className="flex items-center gap-2 text-sm text-gray-500">
                  <FaMapMarkerAlt />
                  <span>{doctor.location}</span>
                </div>
              </div>
              <div className={`px-3 py-1 rounded-full text-xs font-medium ${
                doctor.available 
                  ? 'bg-green-100 text-green-800' 
                  : 'bg-red-100 text-red-800'
              }`}>
                {doctor.available ? t('available') : t('unavailable')}
              </div>
            </div>

            {/* Available Time Slots */}
            <div className="mb-4">
              <h4 className="text-sm font-medium text-gray-700 mb-3 flex items-center gap-2">
                <FaClock className="text-gray-400" />
                Available Time Slots
              </h4>
              <div className="grid grid-cols-3 md:grid-cols-5 gap-2">
                {doctor.slots.map((slot) => (
                  <button
                    key={slot}
                    className="px-3 py-2 border border-gray-200 rounded-lg text-sm font-medium 
                             text-gray-700 hover:bg-primary-light hover:text-primary-color 
                             hover:border-primary-color transition-colors"
                  >
                    {slot}
                  </button>
                ))}
              </div>
            </div>

            {/* Action Buttons */}
            <div className="flex gap-3">
              <button className="btn btn-primary flex-1">
                Book Appointment
              </button>
              <button className="btn btn-outline flex-1">
                View Details
              </button>
            </div>
          </div>
        ))}
      </div>

      {/* No Results */}
      {filteredAvailability.length === 0 && (
        <div className="text-center py-12">
          <FaCalendarAlt className="mx-auto text-6xl text-gray-300 mb-4" />
          <h3 className="text-xl font-medium text-gray-900 mb-2">No availability found</h3>
          <p className="text-gray-600">
            Try adjusting your search criteria or select a different date
          </p>
        </div>
      )}
    </div>
  );
};

export default Availability;
